<script setup lang="ts">import{ref,onMounted}from'vue';import{fetchCoupons}from'@/services/trade';import type{Coupon}from'@/types/trade';const coupons=ref<Coupon[]>([]),errorMessage=ref('');onMounted(async()=>{try{coupons.value=(await fetchCoupons()).list}catch(e){errorMessage.value=e instanceof Error?e.message:'券加载失败'}})</script><template><section class="page-section"><div class="page-header"><div><p class="eyebrow">我的券</p><h1>每张券独立核销，退款和过期状态也各算各的。</h1></div></div><p v-if="errorMessage" class="feedback is-error">{{errorMessage}}</p><div class="rank-grid"><article v-for="c in coupons" :key="c.id" class="rank-card"><img :src="c.coverImage" :alt="c.dealTitle"><div class="rank-card__body"><h2>{{c.dealTitle}}</h2><strong>{{c.code}}</strong><span>{{c.shopName}} · {{c.statusText}} · {{c.expireAt}}</span></div></article></div></section></template>
